# -- Helpers --
import textwrap as _tw

_LINE_WIDTH = 70

def _banner(title):
    print("=" * _LINE_WIDTH)
    pad = (_LINE_WIDTH - len(title) - 2) // 2
    print(" " * pad + " " + title + " " + " " * pad)
    print("=" * _LINE_WIDTH)

def _hr():
    print("-" * _LINE_WIDTH)

def _wrap(text):
    return _tw.wrap(text, width=_LINE_WIDTH - 4,
                    initial_indent="  ", subsequent_indent="    ")

def _show_wrong(raw, wrong_dict):
    exp = wrong_dict.get(raw)
    if exp:
        print()
        for ln in _wrap(f"[wrong] {exp}"):
            print(ln)
    else:
        print(f"  [wrong] {raw!r} is not the correct answer.")

def _show_passphrase(passphrase):
    print()
    _hr()
    print(f"  Passphrase: {passphrase}")
    _hr()
    print()

def die(msg):
    print(f"error: {msg}", file=sys.stderr)
    sys.exit(1)

SCRIPT_DIR = os.path.dirname(os.path.abspath(__file__))
REPO_ZIP   = os.path.join(SCRIPT_DIR, "repo.zip")

def _extract_repo():
    if not os.path.isfile(REPO_ZIP):
        die("repo.zip not found.")
    work_dir = tempfile.mkdtemp(prefix="complexity-clock-")
    with zipfile.ZipFile(REPO_ZIP, "r") as zf:
        zf.extractall(work_dir)
    entries = os.listdir(work_dir)
    if len(entries) != 1:
        shutil.rmtree(work_dir, ignore_errors=True)
        die("unexpected zip structure")
    return work_dir, os.path.join(work_dir, entries[0])

def _make_rcfile(repo_dir):
    banner_text = """
      ============================================================
       Complexity Clock
      ============================================================

       Step 1 -- compile the timing harness:
         make && ./clock
       
       Step 2 -- read the output carefully.
         All four functions compute the same answer.
         Note which ones are fast and which are slow.
       
       Step 3 -- type 'exit' when done.
         A short quiz follows.
      ============================================================

    """
    rcfile = tempfile.NamedTemporaryFile(mode="w", suffix=".rc", delete=False)
    rcfile.write(
        f'PS1=\'\\u@complexity-clock:\\W\\$ \'\n'
        f'cd "{repo_dir}"\n'
        "cat << 'BANNER'\n" + banner_text + "\nBANNER\n"
    )
    rcfile.close()
    return rcfile

def _drop_to_shell(repo_dir):
    rcfile = _make_rcfile(repo_dir)
    shell = os.environ.get("SHELL", "/bin/bash")
    try:
        subprocess.run([shell, "--rcfile", rcfile.name])
    finally:
        try:
            os.remove(rcfile.name)
        except OSError:
            pass

def run_shell_drop_once():
    work_dir, repo_dir = _extract_repo()
    _drop_to_shell(repo_dir)
    return repo_dir, work_dir

def run_shell_drop_with_retry(is_ready, not_ready_lines):
    work_dir, repo_dir = _extract_repo()
    while True:
        _drop_to_shell(repo_dir)
        if is_ready(repo_dir):
            return repo_dir, work_dir
        print()
        for line in not_ready_lines(repo_dir):
            print(line)
        print()
        try:
            again = input("  Try again? [y/n] ").strip().lower()
        except (EOFError, KeyboardInterrupt):
            print()
            shutil.rmtree(work_dir, ignore_errors=True)
            return None, None
        if again != "y":
            shutil.rmtree(work_dir, ignore_errors=True)
            return None, None

def run_shell_drop_validated(check):
    work_dir, repo_dir = _extract_repo()
    try:
        while True:
            _drop_to_shell(repo_dir)
            print()
            _banner("Complexity Clock -- Checking Your Work")
            print()
            passphrase, feedback = check(repo_dir)
            if passphrase is not None:
                _show_passphrase(passphrase)
                return True
            for line in feedback:
                print(line)
            print()
            try:
                again = input("  Try again? [y/n] ").strip().lower()
            except (EOFError, KeyboardInterrupt):
                print()
                return False
            if again != "y":
                return False
            print()
    finally:
        shutil.rmtree(work_dir, ignore_errors=True)

def _secret_for_item(index):
    """Open the encrypted answer/explanation payload for a 1-based item index."""
    secret = _open_secret(ITEM_SECRETS[index - 1], "complexity-clock:question:" + str(index))
    if secret is None:
        print("  [error] Could not open item data -- contact your instructor.")
        sys.exit(1)
    return secret


class ActivityEngine:
    """Core check/passphrase logic for Complexity Clock; importable without a TTY."""

    slug = "complexity-clock"
    title = "Complexity Clock"
    description = 'Four programmers solve the same problem four different ways. All four get the right answer. Count how many times the marked line executes when n = 10 -- then run the clock to see what that means for large n.'

    def items(self):
        """Return the public (non-secret) item dicts, in display order."""
        return QUESTIONS

    def check(self, index, raw):
        """Check a 1-based item's raw answer; return {correct, feedback, explanation}."""
        secret = _secret_for_item(index)
        correct = raw == secret["answer"]
        return {
            "correct": correct,
            "feedback": None if correct else (secret.get("wrong") or {}).get(raw),
            "explanation": secret.get("explanation", "") if correct else None,
        }

    def passphrase(self, answers):
        """Return the unlocked passphrase once all answers are correct, else None."""
        return _decrypt(_BLOB, answers)


ENGINE = ActivityEngine()


def _ask(item, index, total):
    _hr()
    print(f"\n  Q{index:02}/{total:02}  {item['prompt']}")
    for line in item.get("code", "").splitlines():
        print(f"    {line}")
    print(f"\n  {item['prompt']}")
    print(f"  Hint: {item['hint']}")
    while True:
        raw = input("\n  Your answer: ").strip()
        if not raw:
            continue
        result = ENGINE.check(index, raw)
        if result["correct"]:
            print()
            for ln in _wrap(result.get("explanation", "")):
                print(ln)
            return raw
        _show_wrong(raw, {raw: result["feedback"]} if result.get("feedback") else {})
        print("           Enter a whole number and try again.")


def main():
    _banner(ENGINE.title)
    print()
    input("  Press Enter to begin...")

    def _ready(repo_dir):
        return os.path.isfile(os.path.join(repo_dir, "clock"))

    def _not_ready(repo_dir):
        return [
            "  Please compile the program first:",
            "    make && ./clock",

        ]

    repo_dir, work_dir = run_shell_drop_with_retry(_ready, _not_ready)
    if repo_dir is None:
        sys.exit(0)
    shutil.rmtree(work_dir, ignore_errors=True)

    print()
    _hr()
    print("  Good.  Now answer four short questions about what you saw.\n  Trace each function by hand for n = 10.")
    _hr()

    answers = []
    items = ENGINE.items()
    total = len(items)
    for i, item in enumerate(items, 1):
        answers.append(_ask(item, i, total))

    print()
    print("  All correct.")
    passphrase = ENGINE.passphrase(answers)
    if passphrase is None:
        print("  [error] Decryption failed -- contact your instructor.")
        sys.exit(1)
    _show_passphrase(passphrase)


if __name__ == "__main__":
    main()
